use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use std::path::PathBuf;
use walkdir::WalkDir;

async fn handle_file(filename: String) -> impl Responder {
    let uploads_dir = PathBuf::from("./uploads");
    let filepath = uploads_dir.join(filename);

    if filepath.is_file() {
        return HttpResponse::Ok()
            .content_type(get_content_type(&filepath))
            .body(fs_extra::file::read_to_string(&filepath));
    } else {
        return HttpResponse::NotFound().body("File not found");
    }
}

fn get_content_type(file_path: &PathBuf) -> Option<String> {
    let mime_type = mime_guess::from_path(file_path)
        .or(mime_guess::from_extension(file_path.extension()))
        .first()
        .map(|mime| mime.to_string());
    mime_type
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new().service(
            web::resource("/uploads/{filename}")
                .route(web::get().to(handle_file)),
        )
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

